     1→/**
     2→ * OpenAI Token Budget Service
     3→ *
     4→ * Tracks OpenAI token usage across all modalities (LLM, TTS, ASR, Vision, Embedding).
     5→ * When daily budget (100K tokens) is exhausted, signals the AI provider to skip OpenAI
     6→ * and route directly to NIM providers.
     7→ *
     8→ * PERSISTENCE: Token budget state is now persisted to the ai_token_budget_daily DB table
     9→ * so that dashboard data survives server restarts/deploys.
    10→ *
    11→ * Token estimation:
    12→ * - LLM: uses response.usage.total_tokens when available, estimates from text length otherwise
    13→ * - TTS: ~1 token per 4 characters of input text
    14→ * - ASR: ~1 token per second of audio (Whisper pricing model)
    15→ * - Vision: ~85 tokens per image + prompt tokens
    16→ * - Embedding: ~1 token per 4 characters
    17→ */
    18→
    19→const DAILY_BUDGET = parseInt(process.env.OPENAI_DAILY_TOKEN_BUDGET, 10) || 100000;
    20→const pool = require('./db');
    21→
    22→class TokenBudgetService {
    23→  constructor() {
    24→    this.dailyBudget = DAILY_BUDGET;
    25→    this.tokensUsed = 0;
    26→    this.budgetExhausted = false;
    27→    this.currentDay = this._getUTCDay();
    28→    this.history = [];         // Last 7 days of usage
    29→    this.modalityBreakdown = { // Per-modality tracking
    30→      llm: 0,
    31→      tts: 0,
    32→      asr: 0,
    33→      vision: 0,
    34→      embedding: 0,
    35→      other: 0,
    36→    };
    37→    this.providerBreakdown = { // Per-provider tracking (OpenAI vs NIM)
    38→      openai: 0,
    39→      nim: 0,
    40→      other: 0,
    41→    };
    42→    this.exhaustedAt = null;   // Timestamp when budget was exhausted
    43→    this.resetAt = null;       // Next reset time
    44→    this._persistCounter = 0;  // Debounce DB writes
    45→
    46→    this._updateResetTime();
    47→    this._startMidnightReset();
    48→
    49→    // Load persisted state from DB (non-blocking)
    50→    this._loadFromDb();
    51→
    52→    console.log(`[token-budget] Initialized. Daily budget: ${this.dailyBudget.toLocaleString()} tokens`);
    53→  }
    54→
    55→  _getUTCDay() {
    56→    const now = new Date();
    57→    return `${now.getUTCFullYear()}-${String(now.getUTCMonth() + 1).padStart(2, '0')}-${String(now.getUTCDate()).padStart(2, '0')}`;
    58→  }
    59→
    60→  _updateResetTime() {
    61→    const now = new Date();
    62→    const tomorrow = new Date(Date.UTC(
    63→      now.getUTCFullYear(),
    64→      now.getUTCMonth(),
    65→      now.getUTCDate() + 1,
    66→      0, 0, 0, 0
    67→    ));
    68→    this.resetAt = tomorrow.toISOString();
    69→  }
    70→
    71→  _startMidnightReset() {
    72→    // Check every 60 seconds if the day has changed
    73→    this._resetInterval = setInterval(() => {
    74→      const today = this._getUTCDay();
    75→      if (today !== this.currentDay) {
    76→        this._performReset(today);
    77→      }
    78→    }, 60 * 1000);
    79→  }
    80→
    81→  _performReset(newDay) {
    82→    // Save yesterday's usage to DB before resetting
    83→    this._persistToDb().catch(() => {});
